:root {
  --card-bg: #1a1a2e;
  --card-border: #2e2e50;
  --header-accent: #e94560;
  --badge-bg: #e94560;
  --badge-text: #ffffff;
  --title-color: #f0f0f8;
  --price-color: #f0f0f8;
  --price-period-color: #8888aa;
  --gear-item-bg: #16213e;
  --gear-item-border: #2e2e50;
  --gear-name-color: #d0d0e8;
  --gear-tag-color: #8888aa;
  --gear-tag-bg: #0f3460;
  --status-available-bg: #0d3b2e;
  --status-available-text: #2ecc71;
  --status-low-bg: #3b2800;
  --status-low-text: #f39c12;
  --status-unavailable-bg: #3b0d1a;
  --status-unavailable-text: #e74c3c;
  --footer-bg: #16213e;
  --deposit-label-color: #8888aa;
  --deposit-value-color: #f0f0f8;
  --dur-btn-bg: #0f3460;
  --dur-btn-text: #8888aa;
  --dur-btn-active-bg: #e94560;
  --dur-btn-active-text: #ffffff;
  --rent-btn-bg: #e94560;
  --rent-btn-text: #ffffff;
  --icon-bg: #0f3460;
}

.rental-card {
  background-color: var(--card-bg);
  border: 1px solid var(--card-border);
  border-radius: 16px;
  width: 500px;
  overflow: hidden;
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  padding: 20px 20px 16px;
  border-bottom: 1px solid var(--card-border);
}

.header-left {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.category-badge {
  background-color: var(--badge-bg);
  color: var(--badge-text);
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  padding: 3px 10px;
  border-radius: 20px;
  align-self: flex-start;
}

.card-title {
  font-size: 20px;
  font-weight: 700;
  color: var(--title-color);
  margin: 0;
}

.price-block {
  display: flex;
  align-items: baseline;
  gap: 2px;
}

.price-amount {
  font-size: 28px;
  font-weight: 800;
  color: var(--price-color);
}

.price-period {
  font-size: 14px;
  color: var(--price-period-color);
}

.gear-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
  padding: 14px 20px;
}

.gear-item {
  display: flex;
  align-items: center;
  gap: 12px;
  background-color: var(--gear-item-bg);
  border: 1px solid var(--gear-item-border);
  border-radius: 10px;
  padding: 10px 14px;
}

.gear-icon {
  font-size: 20px;
  width: 36px;
  height: 36px;
  background-color: var(--icon-bg);
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.gear-info {
  display: flex;
  flex-direction: column;
  gap: 3px;
  flex: 1;
}

.gear-name {
  font-size: 14px;
  font-weight: 600;
  color: var(--gear-name-color);
}

.gear-tag {
  font-size: 11px;
  font-weight: 600;
  color: var(--gear-tag-color);
  background-color: var(--gear-tag-bg);
  padding: 2px 8px;
  border-radius: 4px;
  align-self: flex-start;
}

.gear-status {
  font-size: 11px;
  font-weight: 700;
  padding: 4px 10px;
  border-radius: 20px;
  flex-shrink: 0;
}

.gear-status.available {
  background-color: var(--status-available-bg);
  color: var(--status-available-text);
}

.gear-status.low {
  background-color: var(--status-low-bg);
  color: var(--status-low-text);
}

.gear-status.unavailable {
  background-color: var(--status-unavailable-bg);
  color: var(--status-unavailable-text);
}

.card-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  background-color: var(--footer-bg);
  padding: 14px 20px;
  border-top: 1px solid var(--card-border);
}

.deposit-info {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.deposit-label {
  font-size: 11px;
  color: var(--deposit-label-color);
  text-transform: uppercase;
  letter-spacing: 0.06em;
  font-weight: 600;
}

.deposit-value {
  font-size: 16px;
  font-weight: 700;
  color: var(--deposit-value-color);
}

.duration-picker {
  display: flex;
  gap: 6px;
}

.dur-btn {
  background-color: var(--dur-btn-bg);
  color: var(--dur-btn-text);
  border: none;
  border-radius: 8px;
  padding: 6px 12px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
}

.dur-btn.active {
  background-color: var(--dur-btn-active-bg);
  color: var(--dur-btn-active-text);
}

.rent-btn {
  background-color: var(--rent-btn-bg);
  color: var(--rent-btn-text);
  border: none;
  border-radius: 10px;
  padding: 10px 20px;
  font-size: 14px;
  font-weight: 700;
  cursor: pointer;
}
